package com.careeros.ai.infrastructure;import org.springframework.boot.context.properties.ConfigurationProperties;import java.time.Duration;@ConfigurationProperties("careeros.ai.ollama")public record OllamaProperties(String baseUrl,String primaryModel,String fastModel,String embeddingModel,Duration timeout){public OllamaProperties{if(baseUrl==null)baseUrl="http://localhost:11434";if(primaryModel==null)primaryModel="llama3.1:8b";if(fastModel==null)fastModel="mistral:7b";if(embeddingModel==null)embeddingModel="nomic-embed-text";if(timeout==null)timeout=Duration.ofMinutes(2);}}
